label("$A$",(-2.1,-2.2),SW);
label("$B$",(3.1,-2.2),SE);
label("$C$",(0.05,0.3),N);
draw(a,(3,0)--(3,-3)--(0,-3)--(0,0));
draw(a,(0,0)--(-4,0)--(-4,4)--(0,4));
draw(a,shift(-2.4,2.2)*rotate(90 - aTan(4/3))*((3,0)--(8,0)--(8,-5)--(3,-5)));
add(currentpicture,rotate(-130)*a);
[/asy]

